import{_ as a,c as e,o as t,aj as r}from"./chunks/framework.CLcCQpUA.js";const p=JSON.parse('{"title":"🔎聚合搜索","description":"","frontmatter":{},"headers":[],"relativePath":"feat/ags.md","filePath":"feat/ags.md"}'),o={name:"feat/ags.md"},i=r('<h1 id="🔎聚合搜索" tabindex="-1">🔎聚合搜索 <a class="header-anchor" href="#🔎聚合搜索" aria-label="Permalink to &quot;🔎聚合搜索&quot;">​</a></h1><h2 id="使用" tabindex="-1">使用 <a class="header-anchor" href="#使用" aria-label="Permalink to &quot;使用&quot;">​</a></h2><p>从下文输入方式获取一组搜索词，然后将多个搜索列表一次性在预览窗口中列出，后面就是常规选择下载流程</p><table><tbody><tr><td><img src="https://jsd.vxo.im/gh/jasoneri/imgur@main/CGS/ags.gif"></td></tr></tbody></table><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><h4 id="_1-qq-消息复制" tabindex="-1">1. qq-消息复制 <a class="header-anchor" href="#_1-qq-消息复制" aria-label="Permalink to &quot;1. qq-消息复制&quot;">​</a></h4><p>在 qq 聊天窗口按住左键区域选择，然后点复制，回 CGS 的 aggrSearch<br> 👉点击 <code>from qq</code> 按钮</p><h4 id="_2-任务文本文件" tabindex="-1">2. 任务文本文件 <a class="header-anchor" href="#_2-任务文本文件" aria-label="Permalink to &quot;2. 任务文本文件&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">格式: 每一行是一个搜索词</p></div><p>任务文件自带状态管理，选择下载后会把文件中对应已选择的行删除，可以用 Langbot 机器人等方式持续集成搜索词到该文件<br> 👉点击 <code>from 文件</code> 按钮</p><h4 id="_3-待扩展" tabindex="-1">3. 待扩展 <a class="header-anchor" href="#_3-待扩展" aria-label="Permalink to &quot;3. 待扩展&quot;">​</a></h4><p>集思广益，可以起草 issue（需要提供输入输出），<br> 或自发 PR 到 2.6-dev 分支，详见 <a href="https://github.com/jasoneri/ComicGUISpider/blob/2.6-dev/utils/ags/extractor.py" target="_blank" rel="noreferrer">utils/ags/extractor.py</a> 参照 qq 实现即可</p><h3 id="搜索词列表" tabindex="-1">搜索词列表 <a class="header-anchor" href="#搜索词列表" aria-label="Permalink to &quot;搜索词列表&quot;">​</a></h3><p>从输入获取搜索词列表后，</p><ul><li>可以自行取消部分勾选</li><li>或文本框修改单个搜索词</li><li>或点右侧恢复按钮恢复（未被内部程序解析处理的）初始文本</li></ul><p>👉最后点击 <code>运行</code> 按钮，即进入预览窗口的常规选择下载流程</p><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="功能相关" tabindex="-1">功能相关 <a class="header-anchor" href="#功能相关" aria-label="Permalink to &quot;功能相关&quot;">​</a></h3><ul><li>目前仅支持 <code>搜索接口</code> 的聚合</li><li>不支持翻页</li></ul><h3 id="🔗适用的网站" tabindex="-1"><a href="/ComicGUISpider/feat/#适用性">🔗适用的网站</a> <a class="header-anchor" href="#🔗适用的网站" aria-label="Permalink to &quot;[🔗适用的网站](/feat/#%E9%80%82%E7%94%A8%E6%80%A7)&quot;">​</a></h3><h3 id="题外话-脑洞" tabindex="-1">题外话（脑洞） <a class="header-anchor" href="#题外话-脑洞" aria-label="Permalink to &quot;题外话（脑洞）&quot;">​</a></h3><p>后续把聚合搜索写进 cgs-cli （命令行工具）后<br> 用 Langbot 之类持续集成到文件，定时跑 cgs-cli，实现 QQ等 向小号持续发词就能全自动下载了<br><s>👮开门！查水表</s></p>',22),l=[i];function s(h,c,d,n,b,u){return t(),e("div",null,l)}const _=a(o,[["render",s]]);export{p as __pageData,_ as default};
